// Базовый шаблон: source: 'spb', answer/solution/hints/teacher — лаконичные
const mk = (id, code, title, text, grade, difficulty, type, module, component, mode='problem', time=10, format='устно', extra={}) => ({
  id, title, text, grade, difficulty, type, module, component,
  source: 'spb', time, format, mode,
  answer: extra.answer || '',
  solution: extra.solution || (window.MMM_SOLUTIONS && window.MMM_SOLUTIONS[id]) || '',
  hints: extra.hints || [],
  teacher: extra.teacher || `Источник: ${code}. Задача предъявляется устно — рисунок не требуется.`,
  similar: extra.similar || [],
  code,
});

